import{_ as a,c as o,o as i,ah as s}from"./chunks/framework.C-x9UAyH.js";const m=JSON.parse('{"title":"Bootstrap 5","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"bootstrap5/bootstrap5.md","filePath":"bootstrap5/bootstrap5.md","lastUpdated":1751473238000}'),t={name:"bootstrap5/bootstrap5.md"};function n(l,e,r,d,c,p){return i(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="bootstrap-5" tabindex="-1">Bootstrap 5 <a class="header-anchor" href="#bootstrap-5" aria-label="Permalink to &quot;Bootstrap 5&quot;">​</a></h1><p>Bootstrap es un marco de diseño web de código abierto que facilita la creación de sitios web y aplicaciones web de aspecto profesional y altamente funcionales.</p><h2 id="rejilla-responsiva" tabindex="-1">Rejilla Responsiva <a class="header-anchor" href="#rejilla-responsiva" aria-label="Permalink to &quot;Rejilla Responsiva&quot;">​</a></h2><p>Bootstrap utiliza un sistema de rejilla flexible basado en CSS que permite la creación de diseños responsivos que se adaptan a diferentes tamaños de pantalla, desde dispositivos móviles hasta computadoras de escritorio. Está basado en un sistema de columnas y filas.</p><ul><li><p>Filas (<code>&lt;div class=&quot;row&quot;&gt;</code>): Son contenedores horizontales que se utilizan para agrupar columnas. Cada fila debe estar contenida en un contenedor principal (por ejemplo, <code>&lt;div class=&quot;container&quot;&gt;</code> o <code>&lt;div class=&quot;container-fluid&quot;&gt;</code>).</p></li><li><p>Columnas (<code>&lt;div class=&quot;col&quot;&gt;</code>): Se utilizan para dividir el espacio horizontal dentro de una fila. Puedes definir el ancho de una columna utilizando clases como col-6 para una columna que ocupe la mitad del ancho de la fila.</p></li></ul><h2 id="componentes-reutilizables" tabindex="-1">Componentes Reutilizables <a class="header-anchor" href="#componentes-reutilizables" aria-label="Permalink to &quot;Componentes Reutilizables&quot;">​</a></h2><p>Bootstrap proporciona una amplia gama de componentes predefinidos, como botones, formularios, barras de navegación y más. Estos componentes se pueden personalizar y reutilizar en todo el sitio.</p><h2 id="personalizacion-y-flexibilidad" tabindex="-1">Personalizacion y Flexibilidad <a class="header-anchor" href="#personalizacion-y-flexibilidad" aria-label="Permalink to &quot;Personalizacion y Flexibilidad&quot;">​</a></h2><p>Aunque Bootstrap proporciona un estilo predeterminado, es altamente personalizable a través de variables CSS y una herramienta de personalización en línea. Esto permite adaptar Bootstrap a los requisitos específicos del proyecto.</p><h2 id="novedades-y-ventajas" tabindex="-1">Novedades y ventajas <a class="header-anchor" href="#novedades-y-ventajas" aria-label="Permalink to &quot;Novedades y ventajas&quot;">​</a></h2><ul><li>Se ha eliminado la dependencia de jQuery, lo que reduce la carga y mejora la velocidad de las páginas web.</li><li>Bootstrap 5 presenta un CSS más liviano y eficiente, lo que resulta en una carga más rápida de las páginas.</li><li>Se han agregado nuevos componentes y utilidades, como las tarjetas de Bootstrap, y se han mejorado las existentes para una experiencia de desarrollo más rica.</li></ul><h2 id="navegacion-y-menus" tabindex="-1">Navegación y menús <a class="header-anchor" href="#navegacion-y-menus" aria-label="Permalink to &quot;Navegación y menús&quot;">​</a></h2><p>Bootstrap proporciona componentes de navegación y menús que facilitan la creación de sistemas de navegación interactivos y fáciles de usar. Algunos de los componentes clave incluyen:</p><ul><li><p>Barra de navegación (<code>&lt;nav class=&quot;navbar&quot;&gt;</code>): Es altamente personalizable y es ideal para crear menús de navegación elegantes y responsivos.</p></li><li><p>Menús desplegables (<code>&lt;div class=&quot;dropdown&quot;&gt;</code>): Son ideales para organizar opciones de navegación adicionales de manera compacta.</p></li></ul><h2 id="formularios-y-controles-de-entrada" tabindex="-1">Formularios y controles de entrada <a class="header-anchor" href="#formularios-y-controles-de-entrada" aria-label="Permalink to &quot;Formularios y controles de entrada&quot;">​</a></h2><p>Bootstrap simplifica la creación de formularios y controles de entrada con componentes predefinidos y estilos uniformes. Algunos de los componentes avanzados incluyen:</p><ul><li><p>Grupos de entrada (<code>&lt;div class=&quot;input-group&quot;&gt;</code>): Estos grupos permiten agregar elementos adicionales, como botones o iconos, a los campos de entrada.</p></li><li><p>Validación de formularios: Bootstrap ofrece estilos y clases para resaltar visualmente campos de entrada válidos e inválidos, lo que mejora la experiencia del usuario.</p></li></ul><h2 id="popovers-y-tooltips" tabindex="-1">Popovers y Tooltips <a class="header-anchor" href="#popovers-y-tooltips" aria-label="Permalink to &quot;Popovers y Tooltips&quot;">​</a></h2><p>Son componentes interactivos que proporcionan información adicional al usuario al hacer clic o pasar el cursor sobre un elemento. Se pueden crear fácilmente con clases como popover y tooltip.</p><ul><li><p>Popover (<code>&lt;a data-toggle=&quot;popover&quot;&gt;</code>): Muestran información adicional en un cuadro emergente cuando se hace clic en un elemento.</p></li><li><p>Tooltip (<code>&lt;a data-toggle=&quot;tooltip&quot;&gt;</code>): Muestran información emergente al pasar el cursor sobre un elemento.</p></li></ul>',20)])])}const v=a(t,[["render",n]]);export{m as __pageData,v as default};
